<template>
  <div class="g-page-container">
    <div class="g-table">
      <!-- 表头 -->
      <div class="cell flex-space-between header">
        <div class="check">
          <el-checkbox
            :model-value="allChecked"
            @update:model-value="allCheckedChange"
            label=""
            size="small"
          />
        </div>
        <div
          v-for="(label, index) in labels"
          :key="index"
          class="name bg"
          :class="label.class"
        >
          {{ label.text }}
        </div>
        <div class="name bg refresh" @click="handleBatchRefresh">批量刷新</div>
      </div>

      <!-- 数据行 -->
      <div
        class="cell flex-space-between"
        v-for="(item, index) in paginatedData"
        :key="index"
        :class="{ checked: item.checked }"
      >
        <div class="check">
          <el-checkbox
            :model-value="item.checked"
            @update:model-value="(val) => checkedChange(item, val)"
            label=""
            size="small"
          />
        </div>
        <div class="name devid">{{ item.devid }}</div>
        <div class="name devname">{{ item.devname }}</div>
        <div class="name devtype">{{ item.devtype }}</div>
        <div class="name devdesp">{{ item.devdesp }}</div>
        <div class="name timestamp">{{ formatTimestamp(item.timestamp) }}</div>
        <div class="name name">{{ item.name }}</div>
        <div class="name pos">{{ item.pos.toFixed(3) }}</div>
        <div class="name speed">{{ item.speed.toFixed(3) }}</div>
        <div class="name current">{{ item.current.toFixed(3) }}</div>
        <div class="name temperature">{{ item.temperature }}</div>
        <div class="name errorcode">{{ item.errorCode }}</div>
        <div class="name refresh" @click.stop="handleSingleRefresh(item)">
          刷新
        </div>
      </div>
    </div>
    <pagination :total="tableData.length" @change="handlePageChange" />
  </div>
</template>

<script setup>
import { ref, computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { ElMessage } from 'element-plus'

import { useCheckbox } from '@/hooks/useCheckbox.js'
import { useCommand } from '@/hooks/useCommand.js'
import { useDataMerge } from '@/hooks/useDataMerge'
import { useSortData } from '@/hooks/useSortData'
import { useTimeFormat } from '@/hooks/useTimeFormat'

const { formatTimestamp } = useTimeFormat()

// store相关
const store = useWslStore()
const { received, isConnected } = storeToRefs(store)
const { sendGetStatusData } = useCommand(store)

// 表头配置
const labels = [
  { text: '设备ID', class: 'devid' },
  { text: '设备名称', class: 'devname' },
  { text: '设备类型', class: 'devtype' },
  { text: '设备描述', class: 'devdesp' },
  { text: '时间', class: 'timestamp' },
  { text: '关节ID', class: 'name' },
  { text: '位置', class: 'pos' },
  { text: '速度', class: 'speed' },
  { text: '电流', class: 'current' },
  { text: '温度', class: 'temperature' },
  { text: '错误码', class: 'errorcode' }
]

// 数据相关
// 1. 计算要显示的数据，合并13和61命令的数据
const motorData = useDataMerge(
  computed(() => received.value?.statusData?.motorDataList)
).mergedData

// 2. 对合并后的数据进行排序
const sortedMotorData = useSortData(motorData, {
  key: 'devid',
  type: 'number',
  order: 'asc'
}).sortedData

// 3. 勾选框使用排序后的数据
const {
  tableData,
  allChecked,
  allCheckedChange,
  checkedChange,
  clearChecked,
  getCheckedItems
} = useCheckbox(sortedMotorData)

// 分页相关
const pageSize = ref(10)
const currentPage = ref(1)

const paginatedData = computed(() => {
  const start = (currentPage.value - 1) * pageSize.value
  const end = start + pageSize.value
  return tableData.value.slice(start, end)
})

// 分页处理
const handlePageChange = (val) => {
  currentPage.value = val.page
  pageSize.value = val.size
  clearChecked()
}

// 单行刷新
const handleSingleRefresh = (item) => {
  if (item.devid) {
    sendGetStatusData('motor', item.devid)
  }
}

// 批量刷新
const handleBatchRefresh = () => {
  const selectedItems = getCheckedItems()
  if (selectedItems.length === 0) {
    ElMessage({
      message: '请选择需要刷新的项',
      type: 'warning'
    })
    return
  }
  const devids = selectedItems.map((item) => item.devid)
  sendGetStatusData('motor', devids)
}

// 等socket连接后发送13命令获取数据
watch(
  () => isConnected.value,
  (newStatus) => {
    if (newStatus) {
      sendGetStatusData('motor')
    }
  },
  { immediate: true }
)
</script>

<style lang="less" scoped>
.name {
  &.devid,
  &.devname,
  &.devtype,
  &.devdesp,
  &.name,
  &.temperature,
  &.errorcode {
    width: 5rem;
  }
  &.timestamp {
    width: 12rem;
  }
  &.pos,
  &.speed,
  &.current {
    width: 5rem;
  }
  &.refresh {
    width: 4rem;
  }
}
</style>
