import { ref, computed } from 'vue'

export function useCheckbox(initialData) {
  const checkedMap = ref(new Map())
  const allChecked = ref(false)

  // 计算表格数据，合并勾选状态
  const tableData = computed(() => {
    if (!initialData.value) return []
    return initialData.value.map((item) => ({
      ...item,
      checked: checkedMap.value.get(item.devid || item.id) || false
    }))
  })

  // 全选/取消全选
  const allCheckedChange = (val) => {
    allChecked.value = val
    if (initialData.value) {
      initialData.value.forEach((item) => {
        checkedMap.value.set(item.devid || item.id, val)
      })
    }
  }

  // 单个勾选变化
  const checkedChange = (item, val) => {
    checkedMap.value.set(item.devid || item.id, val)
    // 检查是否全选
    allChecked.value = initialData.value.every((item) =>
      checkedMap.value.get(item.devid || item.id)
    )
  }

  // 清除选中
  const clearChecked = () => {
    checkedMap.value.clear()
    allChecked.value = false
  }

  // 获取选中的项
  const getCheckedItems = () => {
    return tableData.value.filter((item) => item.checked)
  }

  return {
    tableData,
    allChecked,
    allCheckedChange,
    checkedChange,
    clearChecked,
    getCheckedItems
  }
}
